// Some portions generated by Claude
package org.eclipse.rdf4j.query.algebra.equivalence.internal;

import java.time.Duration;
import java.util.List;

import org.eclipse.rdf4j.query.algebra.TupleExpr;
import org.eclipse.rdf4j.query.algebra.equivalence.AlgebraEquivalenceChecker;
import org.eclipse.rdf4j.query.algebra.equivalence.EquivalenceResult;
import org.eclipse.rdf4j.query.algebra.json.TupleExprJsonParser;
import org.eclipse.rdf4j.query.algebra.json.TupleExprJsonWriteException;
import org.eclipse.rdf4j.query.algebra.json.TupleExprJsonWriter;

/**
 * Drives {@link TreePair}s through the invariant battery: the primary profile on every pair, secondary profiles on
 * every fourth pair, plus a JSON round-trip coherence check. Violations are shrunk and persisted by the optional
 * collaborators so a red run always leaves a reproducible artifact behind.
 */
final class DifferentialFuzzHarness {
	private final DifferentialOracle oracle = new DifferentialOracle();
	private final FuzzProfile primary;
	private final List<FuzzProfile> secondary;
	private final PairShrinker shrinker;
	private final FuzzArtifactWriter artifactWriter;
	private final boolean jsonRoundTrip;

	DifferentialFuzzHarness(FuzzProfile primary, List<FuzzProfile> secondary, PairShrinker shrinker,
			FuzzArtifactWriter artifactWriter, boolean jsonRoundTrip) {
		this.primary = primary;
		this.secondary = secondary;
		this.shrinker = shrinker;
		this.artifactWriter = artifactWriter;
		this.jsonRoundTrip = jsonRoundTrip;
	}

	FuzzRunSummary run(long seed, Iterable<TreePair> pairs, Duration timeBudget) {
		FuzzRunSummary summary = new FuzzRunSummary(seed);
		long deadline = System.nanoTime() + timeBudget.toNanos();
		int index = 0;
		for (TreePair pair : pairs) {
			if (System.nanoTime() > deadline) {
				break;
			}
			summary.recordPair();
			judge(pair, primary, summary);
			if (index % 4 == 3) {
				for (FuzzProfile profile : secondary) {
					judge(pair, profile, summary);
				}
			}
			if (jsonRoundTrip) {
				jsonRoundTrip(pair, summary);
			}
			index++;
		}
		return summary;
	}

	private void judge(TreePair pair, FuzzProfile profile, FuzzRunSummary summary) {
		recordVerdict(pair, profile, summary);
		for (FuzzViolation violation : oracle.judge(pair, profile)) {
			FuzzViolation shrunk = shrinker == null ? violation : shrinker.shrink(violation, profile, oracle);
			if (artifactWriter != null) {
				artifactWriter.write(shrunk, profile);
			}
			summary.record(shrunk);
		}
	}

	private void recordVerdict(TreePair pair, FuzzProfile profile, FuzzRunSummary summary) {
		try {
			EquivalenceResult result = new AlgebraEquivalenceChecker(profile.options())
					.check(pair.original(), pair.candidate());
			summary.recordVerdict(pair.sourceId(), result.getStatus().name());
		} catch (Throwable t) {
			summary.recordVerdict(pair.sourceId(), "THREW");
			// The oracle records the robustness violation; this is bookkeeping only.
		}
	}

	private void jsonRoundTrip(TreePair pair, FuzzRunSummary summary) {
		TupleExprJsonWriter writer = new TupleExprJsonWriter();
		TupleExprJsonParser parser = new TupleExprJsonParser();
		TupleExpr original;
		TupleExpr candidate;
		try {
			original = parser.parse(writer.toJson(pair.original()));
			candidate = parser.parse(writer.toJson(pair.candidate()));
		} catch (TupleExprJsonWriteException e) {
			summary.recordJsonRoundTripSkip();
			return;
		} catch (Throwable t) {
			summary.record(new FuzzViolation(FuzzInvariant.JSON_ROUND_TRIP, primary.label(), pair,
					"round-trip threw " + t.getClass().getSimpleName() + ": " + t.getMessage()));
			return;
		}
		if (!ExactTreeEquality.equal(pair.original(), original)
				|| !ExactTreeEquality.equal(pair.candidate(), candidate)) {
			summary.record(new FuzzViolation(FuzzInvariant.JSON_ROUND_TRIP, primary.label(), pair,
					"parse(write(tree)) is not ExactTreeEquality-equal to the tree"));
			return;
		}
		try {
			EquivalenceResult direct = new AlgebraEquivalenceChecker(primary.options())
					.check(pair.original(), pair.candidate());
			EquivalenceResult roundTripped = new AlgebraEquivalenceChecker(primary.options())
					.check(original, candidate);
			if (direct.getStatus() != roundTripped.getStatus()) {
				summary.record(new FuzzViolation(FuzzInvariant.JSON_ROUND_TRIP, primary.label(), pair,
						"verdict changed across round-trip: " + direct.getStatus() + " -> "
								+ roundTripped.getStatus()));
			}
		} catch (Throwable t) {
			summary.record(new FuzzViolation(FuzzInvariant.JSON_ROUND_TRIP, primary.label(), pair,
					"round-tripped check threw " + t.getClass().getSimpleName() + ": " + t.getMessage()));
		}
	}
}
